sys_script.script:
(function executeRule(current, previous /*null when async*/ ) {

    var payloadTemp;
    var assetTag;
    var resultTemp;
    var check;

    //Create new record for the DB connection logs
    function createLogRecord(payloadTemp, resultTemp) {
        var logs = new GlideRecord("u_ev_db_logs");
        logs.initialize();
        logs.u_payload = payloadTemp;
        logs.u_result = resultTemp;
        logs.insert();
    }

    //Itil role cannot be added to MID Server so record update will be performed by a bot via impersonation
    function performUpdate(deviceSys_id) {
		//VoltCareBox sys_id account
		var origUser = gs.getSession().impersonate('5bdf2fef836b52108eb710c5eeaad3fd');
		gs.log('Impersonated original: ' + origUser);
		var updateBox = new GlideRecord('u_ev_devices');
		updateBox.get(deviceSys_id);
        updateBox.operational_status = 2;
		updateBox.u_active = false;
        updateBox.update();
		var impersonated = gs.getSession().impersonate(origUser);
	}

    // Change payload XML output to JSON
    var jsObj = gs.xmlToJSON(current.payload);
    // XML output very much do not like differencing between one and more records so the proper 'if' is needed to check if there is only one or more...
    var recordNumber = parseInt(current.name);
    if (recordNumber >= 2) {
        check = jsObj.results.result.row.map(row => row.Asset_Tag.content);
    } else {
        check = jsObj.results.result.row.Asset_Tag.content;
    }

    // Check if there is any devices 'non-operational'
    if (JSUtil.nil(check)) {
        payloadTemp = jsObj.results.result.query + '\n' + jsObj.results.result.total_rows;
        resultTemp = 'No Devices found';
        createLogRecord(payloadTemp, resultTemp);
    } else {
        assetTag = check;
        changeDeviceState(assetTag);
    }

    function changeDeviceState(deviceArray) {

        //In case if I only have one device that reports the 'Non-Operational' state
        if (typeof deviceArray === 'string') {
            deviceArray = [deviceArray];
        }
        for (var i = 0; i < deviceArray.length; i++) {
            var foundDevice = deviceArray[i];

            var check = new GlideRecord('u_ev_devices');
            //check.addQuery('u_active', true);
            check.addQuery('asset_tag', foundDevice);
            check.query();

            if (check.hasNext()) {
                while (check.next()) {
                    if (check.operational_status !== 2) {
                        performUpdate(check.sys_id);
                    } else {
                        payloadLog = 'Device ' + foundDevice + ' operational state already at "Non-Operational"';
                        resultLog = 'Sucess';
                        createLogRecord(payloadLog, resultLog);
                    }
                }
            } else {
                gs.log('DB Operational State update did not found any record of a device: ' + foundDevice);
            }
        }
    }
})(current, previous);
